import requests
import json

url = "https://partner.shopeemobile.com/api/v2/ams/edit_product_list_of_targeted_campaign?access_token=access_token&partner_id=partner_id&shop_id=shop_id&sign=sign&timestamp=timestamp"

payload=json.dumps({
  "campaign_id": 101,
  "edit_type": "add",
  "item_list": [
    {
      "item_id": 101,
      "rate": 1.1
    }
  ]
})
headers = {
  'Content-Type': 'application/json'
}
response = requests.RPCRequest("POST",url,headers=headers, data=payload, allow_redirects=False)

print(response.text)
